// Function to merge two halves and count inversions
long long mergeAndCount(int arr[], int temp[], int left, int mid, int right) {
    int i = left;     // Initial index of left subarray
    int j = mid + 1;  // Initial index of right subarray
    int k = left;     // Initial index of merged subarray
    long long invCount = 0;

    while (i <= mid && j <= right) {
        if (arr[i] <= arr[j]) {
            temp[k++] = arr[i++];
        } else {
            temp[k++] = arr[j++];
            invCount += (mid - i + 1); // Count inversions
        }
    }

    // Copy remaining elements of left subarray
    while (i <= mid)
        temp[k++] = arr[i++];
    // Copy remaining elements of right subarray
    while (j <= right)
        temp[k++] = arr[j++];

    // Copy back merged elements to original array
    for (i = left; i <= right; i++)
        arr[i] = temp[i];

    return invCount;
}

// Recursive function to implement modified merge sort
long long mergeSortAndCount(int arr[], int temp[], int left, int right) {
    long long invCount = 0;
    if (left < right) {
        int mid = left + (right - left) / 2;

        invCount += mergeSortAndCount(arr, temp, left, mid);
        invCount += mergeSortAndCount(arr, temp, mid + 1, right);
        invCount += mergeAndCount(arr, temp, left, mid, right);
    }
    return invCount;
}

// Function to be called by user
long long countInversion(int arr[], int n) {
    int *temp = (int *)malloc(n * sizeof(int));
    long long invCount = mergeSortAndCount(arr, temp, 0, n - 1);
    free(temp);
    return invCount;
}

